public class PolymorphismDemo {

    // Overload 1: printInfo(String value)
    // Overload 2: printInfo(int value)
    // Overload 3: printInfo(double value)

    public static void main(String[] args) {
        printInfo("Hello");
        printInfo(42);
        printInfo(3.14);
    }
}

class Shape {
    double area() {
        return 0;
    }
}

// Circle extends Shape: has double radius, override area() = Math.PI * radius * radius

// Rectangle extends Shape: has double width, height, override area() = width * height

public class RuntimePolymorphism {
    public static void main(String[] args) {
        Shape s1 = new Circle(7.0);        // Shape reference, Circle object
        Shape s2 = new Rectangle(4.0, 5.0); // Shape reference, Rectangle object

        System.out.printf("Circle area: %.2f%n", s1.area());
        System.out.printf("Rectangle area: %.2f%n", s2.area());
    }
}

// Reuse Shape, Circle, and Rectangle from the previous task
// (or redefine them here as inner or separate classes)

public class ShapeArray {
    public static void main(String[] args) {
        Shape[] shapes = {
            new Circle(3.0),
            new Rectangle(2.0, 8.0),
            new Circle(5.0),
            new Rectangle(6.0, 6.0)
        };

        double totalArea = 0;
        for (Shape s : shapes) {
            double a = s.area();
            System.out.printf("Area: %.2f%n", a);
            totalArea += a;
        }
        System.out.printf("Total area: %.2f%n", totalArea);
    }
}
